mapper.select:
SELECT m.meeting_id, m.title, m.place_name, m.meeting_date, m.start_time, m.max_members, m.status, s.name sport_name, CONCAT(r.sido," ",r.sigungu," ",COALESCE(r.dong,"")) region_name, (SELECT COUNT(*) FROM meeting_participants mp WHERE mp.meeting_id=m.meeting_id AND mp.status="APPROVED") approved_count FROM meetings m JOIN sports s ON m.sport_id=s.sport_id JOIN regions r ON m.region_id=r.region_id WHERE m.deleted_at IS NULL AND m.sport_id=#{sportId} AND m.region_id=#{regionId} AND m.status=#{status}
AND ( m.title LIKE CONCAT("%",#{keyword},"%") OR m.content LIKE CONCAT("%",#{keyword},"%") )
ORDER BY m.meeting_date ASC, m.start_time ASC
